# @cctt_verify {"v":2,"sym":"sympy.stats.tests.test_compound_rv.test_normal_CompoundDist","kind":"function","src_hash":"0e8606cef2f3a960","in":{"base":"Any"},"out":{"base":"Any","pred":"E(Y) == 1 and P(Y > 1) == S(1) / 2 and P(Y > 5).simplify() == S(1) / 2 - erf(sqrt(10) / 5) / 2 and variance(Y) == variance(X) + 4 ** 2"},"spec":{"lhs":"test_normal_CompoundDist()","rhs":"test_normal_CompoundDist produces the expected output","over":{"base":"Any"},"name":"test_normal_CompoundDist_correct"},"guarantee":"test_normal_CompoundDist produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.stats.tests.test_compound_rv.test_normal_CompoundDist_correct","statement":"Path(test_normal_CompoundDist(x), test_normal_CompoundDist produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"f7c8f7fe1f197965"}
def test_normal_CompoundDist():
    X = Normal('X', 1, 2)
    Y = Normal('X', X, 4)
    assert density(Y)(x).simplify() == sqrt(10)*exp(-x**2/40 + x/20 - S(1)/40)/(20*sqrt(pi))
    assert E(Y) == 1 # it is always equal to mean of X
    assert P(Y > 1) == S(1)/2 # as 1 is the mean
    assert P(Y > 5).simplify() ==  S(1)/2 - erf(sqrt(10)/5)/2
    assert variance(Y) == variance(X) + 4**2 # 2**2 + 4**2
    # https://math.stackexchange.com/questions/1484451/
    # (Contains proof of E and variance computation)


