# @cctt_verify {"v":2,"sym":"sympy.stats.tests.test_compound_rv.test_poisson_CompoundDist","kind":"function","src_hash":"47455b521ddae3a8","in":{"base":"Any"},"out":{"base":"Any","pred":"E(D).simplify() == k * t"},"spec":{"lhs":"test_poisson_CompoundDist()","rhs":"test_poisson_CompoundDist produces the expected output","over":{"base":"Any"},"name":"test_poisson_CompoundDist_correct"},"guarantee":"test_poisson_CompoundDist produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.stats.tests.test_compound_rv.test_poisson_CompoundDist_correct","statement":"Path(test_poisson_CompoundDist(x), test_poisson_CompoundDist produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"f5567f7849979448"}
def test_poisson_CompoundDist():
    k, t, y = symbols('k t y', positive=True, real=True)
    G = Gamma('G', k, t)
    D = Poisson('P', G)
    assert density(D)(y).simplify() == t**y*(t + 1)**(-k - y)*gamma(k + y)/(gamma(k)*gamma(y + 1))
    # https://en.wikipedia.org/wiki/Negative_binomial_distribution#Gamma%E2%80%93Poisson_mixture
    assert E(D).simplify() == k*t # mean of NegativeBinomialDistribution


